// src/ToReprice.js
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './ToReprice.css';
import Optionbar from './Optionbar';
import {
    segmentOptions,
    locationOptions,
    seasonOptions,
    highlightOptions
} from './Icons/optionbarOptions';
import pacman from './Icons/pacman.svg';
import pricesens from './Icons/pricesensitivity.svg';
import euro from './Icons/euro.svg';

const ToReprice = () => {
    // state for loaded items
    const [allItems, setAllItems] = useState([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [sortOrder, setSortOrder] = useState('top');
    const [selectedIndex, setSelectedIndex] = useState(0);
    const [loading, setLoading] = useState(true);

    // load items once on mount
    useEffect(() => {
        setLoading(true);
        axios
            .get(`${process.env.REACT_APP_API_URL || ''}/api/menu-items`, {
                withCredentials: true
            })
            .then((res) => {
                // map your API shape into the shape this component expects
                const mapped = res.data.map((i) => ({
                    name: i.item_name,
                    currentPrice: i.price,
                    minPrice: i.floor_price,
                    optimalPrice: i.low_price,
                    maxPrice: i.ceiling_price,
                    // placeholder until you derive from API
                    cannibalisationRisk: 'medium',
                    priceSensitivity: 'medium',
                    jouwPrijsIs: 'goed'
                }));
                setAllItems(mapped);
            })
            .catch((err) => {
                console.error('Failed loading menu items', err);
            })
            .finally(() => setLoading(false));
    }, []);

    if (loading) return <p>Loading items…</p>;

    // sort + filter
    const sortedItems = [...allItems].sort((a, b) => {
        if (sortOrder === 'top') {
            return b.currentPrice - a.currentPrice;
        } else {
            return a.currentPrice - b.currentPrice;
        }
    });
    const filteredItems = sortedItems.filter((item) =>
        item.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
    const selectedItem = filteredItems[selectedIndex] || {};

    // compute bar positions
    const currentPrice = selectedItem.currentPrice ?? 0;
    const optimalPrice = selectedItem.optimalPrice ?? 0;
    const minPrice = selectedItem.minPrice ?? 0;
    const maxPrice = selectedItem.maxPrice ?? 1;
    const toPct = (p) => ((p - minPrice) / (maxPrice - minPrice)) * 100;
    const thresholds = [
        minPrice,
        (optimalPrice + minPrice) / 2,
        optimalPrice,
        (optimalPrice + maxPrice) / 2,
        maxPrice
    ];
    const segmentClasses = [
        'segment--low',
        'segment--below-optimal',
        'segment--optimal',
        'segment--above-optimal',
        'segment--high'
    ];

    return (
        <div className="to-reprice-container">
            <div className="centre-content">
                <div className="reprice-section">
                    <h2 className="reprice-title">Price Elasticity</h2>
                    <div className="price-bar-wrapper">
                        {thresholds.map((t, i) => (
                            <div
                                key={i}
                                className={`price-threshold-label ${
                                    i === 0 || i === thresholds.length - 1 ? 'end' : ''
                                }`}
                                style={{ left: `calc(${toPct(t)}% - 12px)` }}
                            >
                                €{t.toFixed(2)}
                            </div>
                        ))}
                        <div
                            className="price-bar"
                            style={{
                                display: 'flex',
                                height: '8px',
                                width: '100%',
                                margin: '0 12px'
                            }}
                        >
                            {thresholds.slice(1).map((t, idx) => {
                                const width = thresholds[idx + 1] - thresholds[idx];
                                return (
                                    <div
                                        key={idx}
                                        className={`segment ${segmentClasses[idx]}`}
                                        style={{ flex: width }}
                                    />
                                );
                            })}
                        </div>
                        <div
                            className="price-indicator top"
                            style={{ left: `calc(${toPct(optimalPrice)}% - 8px)` }}
                        />
                        <div
                            className="price-label top"
                            style={{ left: `calc(${toPct(optimalPrice)}% - 8px)` }}
                        >
                            €{optimalPrice.toFixed(2)} best price
                        </div>
                        <div
                            className="price-indicator bottom"
                            style={{ left: `calc(${toPct(currentPrice)}% - 8px)` }}
                        />
                        <div
                            className="price-label bottom"
                            style={{ left: `calc(${toPct(currentPrice)}% - 8px)` }}
                        >
                            €{currentPrice.toFixed(2)} current price
                        </div>
                    </div>

                    <div className="reprice-indicators">
                        <div className="cannibalism">
                            <img src={pacman} className="pacman-icon" alt="" />
                            <div className="cannibalism-label">Cannibalism</div>
                            <div className="cannibalism-indicator">
                                {selectedItem.cannibalisationRisk}
                            </div>
                        </div>
                        <div className="pricesens">
                            <img src={pricesens} className="pricesens-icon" alt="" />
                            <div className="pricesens-label">Price Sensitivity</div>
                            <div className="pricesens-indicator">
                                {selectedItem.priceSensitivity}
                            </div>
                        </div>
                        <div className="yourprice">
                            <img src={euro} className="euro-icon" alt="" />
                            <div className="yourprice-label">Your Price</div>
                            <div className="yourprice-indicator">
                                {selectedItem.jouwPrijsIs}
                            </div>
                        </div>
                    </div>
                </div>

                <div className="reprice-items-section">
                    <div className="r-list-header">
                        <h2 className="header-title">To Reprice Items</h2>
                        <div className="r-search-bar">
                            <input
                                type="text"
                                placeholder="Search"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>
                    </div>
                    <ul className="items-list">
                        {filteredItems.map((item, idx) => (
                            <li
                                key={item.name}
                                className={`item ${
                                    selectedIndex === idx ? 'selected' : ''
                                }`}
                                onClick={() => setSelectedIndex(idx)}
                            >
                <span>
                  {idx + 1}. {item.name}
                </span>
                                <div className="verandering-prijs">
                                    <div className="lijst-jouw-prijs">
                                        <div>€ {item.currentPrice.toFixed(2)}</div>
                                        <div>jouw prijs</div>
                                    </div>
                                    <div className="lijst-pijl">&#8594;</div>
                                    <div className="lijst-nieuwe-prijs">
                                        <div>€ {item.optimalPrice.toFixed(2)}</div>
                                        <div>betere prijs</div>
                                    </div>
                                </div>
                                <div className="lijst-indicator">
                                    <div>Jouw prijs is</div>
                                    <div>{item.jouwPrijsIs}</div>
                                </div>
                            </li>
                        ))}
                    </ul>
                </div>
            </div>

            <Optionbar
                filters={{
                    segments: new Set(segmentOptions.map((o) => o.id)),
                    highlights: new Set(highlightOptions.map((o) => o.id)),
                    seasons: new Set(seasonOptions.map((o) => o.id)),
                    locations: new Set(locationOptions.map((o) => o.id))
                }}
                onChange={() => {}}
            />
        </div>
    );
};

export default ToReprice;
